156: 
157:   <div class="foot">
158:     <span class="pill">Demo dataset · 49 sample programs under the “AWP Labs” EPS</span><br>
159:     Figures computed directly from the P6 SQLite source — identical to the Power BI template.
160:     Diagnostic aid, not a scorecard · <a href="https://awplabs.cl">awplabs.cl</a> · contact@awplabs.cl
161:   </div>
162: </div>
163: 
164: <script>
165: const DATA = __DATA__;
166: const CARD_ORDER = __ORDER__;
167: 
168: const C = {good:'#10B981', neutral:'#F59E0B', bad:'#EF4444', null:'#64748B'};
169: 
170: function statusStructural(v, type){
171:   // v = violation rate (0..1). Returns key in C.
172:   if(type==='zero')     return v>0     ? 'bad' : 'good';
173:   if(type==='binary10') return v>=0.10 ? 'bad' : 'good';   // binary: no amber band (match .pbix)
174:   if(type==='binary5')  return v>=0.05 ? 'bad' : 'good';
175:   if(type==='binary2')  return v>=0.02 ? 'bad' : 'good';
176:   if(type==='tight')    return v>=0.05 ? 'bad' : (v>0 ? 'neutral':'good');
177:   /* standard */        return v>=0.10 ? 'bad' : (v>=0.05 ? 'neutral':'good');
178: }
179: function statusIndex(v){ if(v===null||v===undefined) return 'null'; return v>=0.95?'good':'bad'; }
180: function statusKpi(q){ return q>=0.85?'good':(q>=0.70?'neutral':'bad'); }
181: 
182: const fmtPct = v => (v*100).toFixed(1).replace(/\.0$/,'') + '%';
183: const fmtIdx = v => (v===null||v===undefined) ? 'N/A' : v.toFixed(2);
184: function fmtDate(s){
185:   if(!s) return '—';
186:   const d = new Date(String(s).replace(' ','T'));
187:   if(isNaN(d)) return String(s).slice(0,10);
188:   return d.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'});
189: }
190: const THLABEL = {
191:   standard:'Green &lt;5% · Amber 5–10% · Red ≥10%',
192:   tight:'Green 0% · Amber 0–5% · Red ≥5%',
193:   zero:'Green 0% · Red any occurrence',
194:   binary10:'Green &lt;10% · Red ≥10%',
195:   binary5:'Green &lt;5% · Red ≥5%',
196:   binary2:'Green &lt;2% · Red ≥2%'
197: };
198: 
199: function gauge(q){
200:   const st = statusKpi(q), col = C[st];
201:   const pct = Math.max(0,Math.min(1,q));
202:   const r=82, c=2*Math.PI*r, off=c*(1-pct);
203:   return `<svg viewBox="0 0 188 188">
204:     <circle cx="94" cy="94" r="${r}" stroke="#0e1a30" stroke-width="14" fill="none"/>
205:     <circle cx="94" cy="94" r="${r}" stroke="${col}" stroke-width="14" fill="none"
206:       stroke-linecap="round" stroke-dasharray="${c}" stroke-dashoffset="${off}"
207:       transform="rotate(-90 94 94)"/>
208:   </svg>
209:   <div class="num"><b style="color:${col}">${fmtPct(q)}</b><span>LOOKING FOR HEALTHY</span></div>`;
210: }
211: 
212: function render(p){
213:   // stat strip
214:   const critPct = p.task_total ? (p.crit_count/p.task_total) : 0;
215:   document.getElementById('stats').innerHTML = [
216:     ['Schedule', p.name, ''],
217:     ['Data date', fmtDate(p.data_date), 'sm'],
218:     ['Activities', p.task_total, ''],
219:     ['Completed', p.completed, ''],
220:     ['Critical %', fmtPct(critPct), ''],
221:     ['Relationships', p.rel_total, ''],
222:     ['Start → Finish', fmtDate(p.proj_start)+' → '+fmtDate(p.proj_end), 'sm'],
223:   ].map(([k,v,c])=>`<div class="stat"><div class="k">${k}</div><div class="v ${c}">${v}</div></div>`).join('');
224: 
225:   // hero gauge
226:   document.getElementById('gauge').innerHTML = gauge(p.quality_kpi);
227: 
228:   // cards
229:   const mById = {}; p.metrics.forEach(m=>mById[m.key]=m);
230:   let html='';
231:   let n=0;
232:   for(const [key,badge] of CARD_ORDER){
233:     n++;
234:     const m = mById[key];
235:     const st = statusStructural(m.violation, m.threshold);
236:     const col = C[st];
237:     const w = Math.min(100, m.violation*100*4); // visual scale
238:     html += card(n, badge, m.label, fmtPct(m.violation), `${m.count} / ${m.denom}`,
239:                  col, w, THLABEL[m.threshold]);
240:   }
241:   // CPLI (16) + BEI (17) — index metrics
242:   const cpliSt = statusIndex(p.cpli), cpliCol=C[cpliSt];
243:   const cd = p.cpli_detail||{};
244:   html += card(16,'DCMA-14','CPLI · Critical Path Length Index', fmtIdx(p.cpli),
245:       p.cpli===null?'no remaining critical work':`CPL ${cd.cpl_days||0}d · float ${(cd.crit_float_days||0).toFixed(1)}d`,
246:       cpliCol, p.cpli!==null?Math.min(100,p.cpli*100):0, 'Pass ≥ 0.95 (1.00 = on plan)', true);
247:   const beiSt = statusIndex(p.bei), beiCol=C[beiSt];
248:   const bd = p.bei_detail;
249:   html += card(17,'DCMA-14','BEI · Baseline Execution Index', fmtIdx(p.bei),
250:       bd? `${bd.completed} done / ${bd.due} due · base ${bd.baseline}` : 'No P6 baseline assigned',
251:       beiCol, p.bei!==null&&p.bei!==undefined?Math.min(100,p.bei*100):0, 'Pass ≥ 0.95 · N/A without baseline', true);
252: 
253:   // ===== NEW METRICS 18–22 (standalone, like CPLI/BEI — not folded into the KPI roll-up) =====
254:   const nw = p.new || {};
255:   // 18 Relationship Types — links that are NOT Finish-to-Start (DCMA #4)
256:   const rt = nw.rel_types;
257:   if(rt){ const c=C[statusStructural(rt.violation, rt.threshold)];
258:     html += card(18, rt.badge, 'Relationship Types', fmtPct(rt.violation),
259:       `${rt.count} / ${rt.denom} · non-FS links`, c, Math.min(100, rt.violation*100*4), THLABEL[rt.threshold]); }
260:   // 19 Missed Tasks — baseline-due not finished on time (DCMA #11; N/A without baseline)
261:   const ms = p.missed;
262:   const msC = C[ ms ? (ms.violation>=0.05?'bad':'good') : 'null' ];
263:   html += card(19,'DCMA-14','Missed Tasks', ms?fmtPct(ms.violation):'N/A',
264:       ms? `${ms.count} missed / ${ms.due} due · base ${ms.baseline}` : 'No P6 baseline assigned',
265:       msC, ms?Math.min(100, ms.violation*100):0, 'Pass &lt;5% · Red ≥5% · N/A without baseline');
266:   // 20 Resources — work activities with no resource assignment (DCMA #10)
267:   const rs = nw.resources;
268:   if(rs){ const c=C[statusStructural(rs.violation, rs.threshold)];
269:     html += card(20, rs.badge, 'Resources', fmtPct(rs.violation),
270:       `${rs.count} / ${rs.denom} · no assignment`, c, Math.min(100, rs.violation*100*4), THLABEL[rs.threshold]); }
271:   // 21 Critical Path Test — forecast-finish activity must be critical (DCMA #12)
272:   const cp = p.crit_path;
273:   const cpPass = cp && cp.passed;
